import React, { useState, useContext } from 'react';
import { toast } from 'react-toastify';
import { AuthContext } from '../context/AuthContext';

const CommentForm = ({ onSubmit, isSubmitting }) => {
  const [text, setText] = useState('');
  const { user } = useContext(AuthContext);

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!user) {
      toast.error('Please log in to add a comment');
      return;
    }
    
    if (!text.trim()) {
      toast.error('Comment cannot be empty');
      return;
    }
    
    const success = await onSubmit(text);
    if (success) {
      setText('');
    }
  };

  return (
    <form onSubmit={handleSubmit} className="w-full">
      {!user ? (
        <div className="bg-yellow-50 dark:bg-yellow-900/30 border border-yellow-200 dark:border-yellow-700 rounded-md p-4 mb-4">
          <p className="text-yellow-700 dark:text-yellow-400 text-sm">
            Please log in to add comments to this post.
          </p>
        </div>
      ) : (
        <>
          <div className="mb-4">
            <textarea
              className="w-full px-3 py-2 text-gray-700 dark:text-gray-200 border rounded-lg bg-white dark:bg-gray-700 focus:outline-none focus:ring-2 focus:ring-green-500 dark:border-gray-600"
              rows="4"
              placeholder="Add your comment..."
              value={text}
              onChange={(e) => setText(e.target.value)}
              disabled={isSubmitting}
            ></textarea>
          </div>
          <div className="flex justify-end">
            <button
              type="submit"
              disabled={isSubmitting || !text.trim()}
              className={`px-4 py-2 bg-green-600 text-white rounded-md hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-green-500 focus:ring-opacity-50 transition-colors duration-200 ${
                isSubmitting || !text.trim() ? 'opacity-50 cursor-not-allowed' : ''
              }`}
            >
              {isSubmitting ? 'Posting...' : 'Post Comment'}
            </button>
          </div>
        </>
      )}
    </form>
  );
};

export default CommentForm;
